head.script:
scwin.g_sCurrDate = $c.date.getServerDateTime("yyyyMMdd");
scwin.sAcctDeptCd = $c.data.getMemInfo("acctDeptCd");
scwin.sAppDeptNm  = $c.data.getMemInfo("acctDeptNm");

scwin.onpageload = function() {
};


scwin.onUdcCompleted = function() {
	ed_stdYm.setValue(scwin.g_sCurrDate.substring(0, 6));
	ed_appDept.setValue(scwin.sAcctDeptCd);
    ed_appDeptNm.setValue(scwin.sAppDeptNm);
};

scwin.f_openPopUp = function(gbn=2) {

    let searchType = (gbn==2) ? 'T' : 'F';
    udc_comCodeAppDeptNm.ilCommonPopUp(
        scwin.udc_comCodeAppDeptNm_callBackFunc
        , ed_appDept.getValue()				// 화면에서의 ??? Code Element의	Value
        , ed_appDeptNm.getValue()                   // 화면에서의 ??? Name Element의	Value
        , searchType	                    		// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
        , null			                    		// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
        , null			                    		// Title순서	
        , null			                    		// 보여주는 각 컬럼들의 폭	
        , null				                    	// 컬럼중에서 숨기는	컬럼 지정	
        , null				                    	// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
        , null				                    	// POP-UP뛰을때 원도우의	사용자 정의	폭
        , null				                    	// POP-UP뛰을때 우도우의	사용자 정의	높이	
        , null				                    	// 윈도우 위치 Y좌표	
        , null				                    	// 윈도우 위치 X좌표
        , null				                       	// 중복체크여부	("F")
        , null				                    	// 전체검색허용여부	("F")
        , null	             // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
    );
}

scwin.udc_comCodeAppDeptNm_callBackFunc = function (ret) {
    $c.gus.cfSetReturnValue(ret, ed_appDept, ed_appDeptNm);
};


scwin.f_chkOpenCommonPopUp = function(inObj, pairObj) {

     // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    scwin.f_openPopUp();
}


scwin.udc_comCodeAppDeptNm_onclickEvent = function (e) {
    scwin.f_openPopUp(1);
}


scwin.udc_comCodeAppDeptNm_onblurCodeEvent = function (e) {

    if (ed_appDept.getValue().trim() == '') {
        ed_appDeptNm.setValue('');
        return;
    }
    scwin.f_chkOpenCommonPopUp(ed_appDept, ed_appDeptNm);

};

scwin.udc_comCodeAppDeptNm_onviewchangeNameEvent = function (info) {
   scwin.f_chkOpenCommonPopUp(ed_appDeptNm, ed_appDept, 1);
};


//-------------------------------------------------------------------------
// 오즈 검색 후 결과를 화면 하단에 표시
//-------------------------------------------------------------------------

scwin.f_Search = async function() {

    if (ed_appDept.getValue() == '') {
        $c.win.alert("사용부서은(는) 필수 입력 항목입니다.");
		return false;
    }

    if (ed_stdYm.getValue() == '') {
        $c.win.alert("사용년월은(는) 필수 입력 항목입니다.");
		return false;
    }

    if (ed_stdYm.getValue().length != 6) {
        $c.win.alert("사용년월은(는) 6자리수만큼 입력하십시오.");
		return false;
    }

    let sPostYn = acb_postYn.getValue() + "";
    let data = {
        reportName: "/il/acc/ac_303_01_02.ozr",
        odiParam : {
            CLOSE_YM: ed_stdYm.getValue(), // ds_retrieve.getCellData(row, "cvsslMgntNo"
            DEPT_CD: ed_appDept.getValue(), // ds_retrieve.getCellData(row, "rltNo")
            DEPT_NM: ed_appDeptNm.getValue(),  //ds_retrieve.getCellData(row, "stockMgntNo")
			POST_YN: sPostYn
        },

        viewerParam : {
            useprogressbar : true, // 프로그레스바 쓸지 말지
            zoom : 90, // 배율 설정
			printcommand : false
        },

        formParam : {

        }
    };
    wfm_ozReport.getWindow().mf_scwin.reportSearch(data);
};
